desc_fixes = {
    149: "Петряков объясняет как строить работу на системах а не мотивации — планирование, захват идей, глубокая работа и правильная среда.",
    150: "Рэпер и блогер Моргенштерн о честности с собой: аутентичность как стратегия, год трезвости, эмиграция и настоящая цена хайпа.",
    151: "Геннадий М объясняет почему здоровье — главный капитал, а деньги работают только когда понимаешь финансовую систему изнутри.",
    152: "Воронович объясняет как перепрограммировать реальность через сознание. Трансёрфинг, Высшее Я и жизнь без работы из страха и нужды.",
    153: "Мэлстрой — стример который проиграл миллионы в казино и говорит об этом открыто. О лудомании, хайпе и настоящей цене публичности.",
}

with open('/root/books/webapp/books.json', 'r', encoding='utf-8') as f:
    books = json.load(f)

target = set(appends.keys()) | set(desc_fixes.keys())
for b in books:
    bid = b['id']
    if bid not in target: continue
    if bid in desc_fixes:
        b['description'] = desc_fixes[bid]
    for t in b.get('thoughts', []):
        if 'life' in t:
            del t['life']
    for i, t in enumerate(b['thoughts']):
        if bid in appends and i in appends[bid]:
            t['example'] += appends[bid][i]
        t['example'] = trim_to_fit(t['title'], t['example'])

with open('/root/books/webapp/books.json', 'w', encoding='utf-8') as f:
    json.dump(books, f, ensure_ascii=False, separators=(',', ':'))

print("=== VERIFY blogery_1 ===")
issues = []
for b in books:
    if b['id'] not in target: continue
    d = len(b.get('description', ''))
    if not(125<=d<=150): issues.append(f"ID {b['id']} DESC BAD({d}): {b['description'][:60]}")
    for i, t in enumerate(b['thoughts']):
        total = len(t['title']) + len(t['example'])
        s = 'OK' if 700<=total<=800 else ('SHORT' if total<700 else 'LONG')
        if s != 'OK': issues.append(f"ID {b['id']} t{i} {s}={total}: {t['title'][:40]}")
if issues:
    print("ISSUES:"); [print(" ", x) for x in issues]
else:
    print("All OK!")
